// ─────────────────────────────────────────────────────────────────────────────
// EXPORT UTILITIES — Excel (SheetJS) + PDF (jsPDF)
// ─────────────────────────────────────────────────────────────────────────────
const AGBC_COMPANY = "Al Ghaith Building Construction Co. LLC";
const AGBC_LOGO_B64 = "";
const AMBER_COLOR = [245, 158, 11];
const DARK_COLOR  = [30, 41, 59];
const LIGHT_COLOR = [248, 250, 252];
const todayExport = () => new Date().toISOString().split("T")[0];

const exportToExcel = (data, columns, fileName) => {
  if (!data || data.length === 0) { alert("No data to export."); return; }
  try {
    const XLSX = window._XLSX;
    if (!XLSX) { alert("Excel library not loaded. Please wait and try again."); return; }
    const fullName = `${fileName}_${todayExport()}.xlsx`;
    const headers = columns.map(c => c.header);
    const rows = data.map(row => columns.map(c => {
      const v = row[c.key];
      if (v === null || v === undefined || v === "") return "";
      if (c.type === "date") { try { return new Date(v).toLocaleDateString("en-GB"); } catch { return String(v); } }
      if (c.type === "array") return Array.isArray(v) ? v.join(", ") : String(v);
      if (c.type === "number") return Number(v) || 0;
      return String(v);
    }));
    const wsData = [headers, ...rows];
    const ws = XLSX.utils.aoa_to_sheet(wsData);
    ws["!cols"] = columns.map(c => ({ wch: c.width || 20 }));
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, fileName.replace(/_/g, " ").substring(0, 31));
    XLSX.writeFile(wb, fullName);
  } catch(e) { console.error("Excel export error:", e); alert("Excel export failed: " + e.message); }
};

const exportToPDF = (data, columns, fileName, title, orientation = "landscape") => {
  if (!data || data.length === 0) { alert("No data to export."); return; }
  try {
    const { jsPDF } = window.jspdf;
    if (!jsPDF) { alert("PDF library not loaded. Refresh page and try again."); return; }
    const fullName = `${fileName}_${todayExport()}.pdf`;
    const now = new Date().toLocaleString("en-GB", { dateStyle: "medium", timeStyle: "short" });
    const doc = new jsPDF({ orientation, format: "a4", compress: true });
    const pageW = doc.internal.pageSize.getWidth();
    const pageH = doc.internal.pageSize.getHeight();
    const isPortrait = pageW < pageH;
    const MARGIN = 10;

    // ── LOGO DIMENSIONS ────────────────────────────────────────────────────
    // Logo aspect ratio = width:height ≈ 4.7:1 (wide banner)
    // Portrait A4 usable = 190mm, Landscape = 277mm
    // Logo takes left ~60%, title on right ~38%
    const LOGO_ASPECT = 4.7;
    const HDR_H = isPortrait ? 36 : 40;           // header bar height
    const LOGO_H = HDR_H - 8;                     // logo height with 4mm top/bottom padding
    const LOGO_MAX_W = (pageW - MARGIN * 2) * 0.58; // max 58% of usable width
    const LOGO_W = Math.min(LOGO_H * LOGO_ASPECT, LOGO_MAX_W);
    const LOGO_X = MARGIN;
    const LOGO_Y = (HDR_H - LOGO_H) / 2;          // vertically centred
    const TITLE_X = LOGO_X + LOGO_W + 5;           // title starts after logo
    const TITLE_W = pageW - MARGIN - TITLE_X;      // remaining width for title

    // ── DRAW HEADER (called on every page) ─────────────────────────────────
    const drawHeader = () => {
      // Dark background
      doc.setFillColor(...DARK_COLOR);
      doc.rect(0, 0, pageW, HDR_H, "F");
      // Amber accent bar
      doc.setFillColor(...AMBER_COLOR);
      doc.rect(0, HDR_H, pageW, 2.5, "F");

      // Company logo (left side)
      try {
        doc.addImage(
          "data:image/jpeg;base64," + AGBC_LOGO_B64,
          "JPEG", LOGO_X, LOGO_Y, LOGO_W, LOGO_H
        );
      } catch(e) {
        doc.setTextColor(245, 158, 11);
        doc.setFontSize(12);
        doc.setFont("helvetica", "bold");
        doc.text("AGBC", LOGO_X + 2, HDR_H / 2 + 4);
      }

      // Report title — right-aligned in remaining space, vertically centred
      const titleFontSize = isPortrait ? 10 : 12;
      const subFontSize = 6.5;
      const titleLines = doc.splitTextToSize(title, TITLE_W);
      const titleY = titleLines.length > 1
        ? HDR_H / 2 - (titleLines.length * titleFontSize * 0.3528 / 2)
        : HDR_H / 2 - 1;

      doc.setTextColor(255, 255, 255);
      doc.setFontSize(titleFontSize);
      doc.setFont("helvetica", "bold");
      titleLines.forEach((line, i) => {
        doc.text(line, pageW - MARGIN, titleY + i * (titleFontSize * 0.4), { align: "right" });
      });

      // Date & count (subtle, small)
      doc.setFontSize(subFontSize);
      doc.setFont("helvetica", "normal");
      doc.setTextColor(160, 160, 160);
      doc.text(`${now}  ·  ${data.length} records`, pageW - MARGIN, HDR_H - 5, { align: "right" });
    };

    drawHeader();

    // ── TABLE SETUP ────────────────────────────────────────────────────────
    const heads = [columns.map(c => c.header)];
    const rows = data.map(row => columns.map(c => {
      const v = row[c.key];
      if (v === null || v === undefined || v === "") return "—";
      if (c.type === "date") {
        try { return new Date(v).toLocaleDateString("en-GB"); } catch { return String(v); }
      }
      if (c.type === "array") return Array.isArray(v) ? v.join(", ") : String(v);
      return String(v);
    }));

    // Auto-scale: more columns → smaller font on portrait
    const colCount = columns.length;
    const autoFont = isPortrait
      ? (colCount > 8 ? 6 : colCount > 5 ? 6.5 : 7.5)
      : (colCount > 10 ? 6.5 : colCount > 7 ? 7 : 7.5);
    const autoPad = autoFont < 7 ? 2 : 3;

    // If pdfWidth columns defined → use them, else let autoTable distribute evenly
    const hasPdfWidths = columns.some(c => c.pdfWidth);
    const colStyles = columns.reduce((acc, c, i) => {
      if (hasPdfWidths && c.pdfWidth) acc[i] = { cellWidth: c.pdfWidth };
      if (c.align) acc[i] = { ...(acc[i] || {}), halign: c.align };
      return acc;
    }, {});

    doc.autoTable({
      startY: HDR_H + 5,
      margin: { left: MARGIN, right: MARGIN, bottom: 14 },
      head: heads,
      body: rows,
      theme: "grid",
      // "auto" = shrink to content; "wrap" = fill full table width
      tableWidth: hasPdfWidths ? "auto" : "wrap",
      styles: {
        fontSize: autoFont,
        cellPadding: { top: autoPad, bottom: autoPad, left: 3, right: 3 },
        overflow: "linebreak",
        valign: "middle",
        textColor: [30, 41, 59],
        lineColor: [220, 220, 220],
        lineWidth: 0.2,
        minCellWidth: 10,
      },
      headStyles: {
        fillColor: AMBER_COLOR,
        textColor: [255, 255, 255],
        fontStyle: "bold",
        fontSize: autoFont,
        halign: "center",
        cellPadding: { top: autoPad + 1, bottom: autoPad + 1, left: 3, right: 3 },
      },
      alternateRowStyles: { fillColor: [248, 250, 252] },
      columnStyles: colStyles,
      didDrawPage: ({ pageNumber }) => {
        if (pageNumber > 1) drawHeader();
        // Footer — page numbers only
        const total = doc.internal.getNumberOfPages();
        doc.setFontSize(7);
        doc.setTextColor(160);
        doc.setFont("helvetica", "normal");
        doc.text(`${pageNumber} / ${total}`, pageW / 2, pageH - 5, { align: "center" });
      },
    });

    doc.save(fullName);
  } catch(e) { console.error("PDF export error:", e); alert("PDF export failed: " + e.message); }
};

// ─── COMPREHENSIVE PROJECT PROGRESS REPORT ────────────────────────────────────
const exportProjectReportPDF = async (sel, pgItems, overallPct, projPhotos = []) => {
  try {
    const { jsPDF } = window.jspdf;
    if (!jsPDF) { alert("PDF library not loaded. Refresh and try again."); return; }
    const doc     = new jsPDF({ orientation:"portrait", format:"a4", compress:true });
    const pageW   = doc.internal.pageSize.getWidth();
    const pageH   = doc.internal.pageSize.getHeight();
    const MARGIN  = 12;
    const usableW = pageW - MARGIN * 2;
    const now     = new Date().toLocaleString("en-GB",{dateStyle:"medium",timeStyle:"short"});
    const today   = new Date().toLocaleDateString("en-GB").replace(/\//g,"-");

    // Header constants
    const HDR_H  = 38;
    const LOGO_H = HDR_H - 8;
    const LOGO_W = Math.min(LOGO_H * 4.7, usableW * 0.55);
    const LOGO_X = MARGIN;
    const LOGO_Y = (HDR_H - LOGO_H) / 2;
    let pgCount  = 0;

    const drawHeader = () => {
      pgCount++;
      doc.setFillColor(30,41,59);   doc.rect(0,0,pageW,HDR_H,"F");
      doc.setFillColor(245,158,11); doc.rect(0,HDR_H,pageW,2.5,"F");
      try {
        doc.addImage("data:image/jpeg;base64,"+AGBC_LOGO_B64,"JPEG",LOGO_X,LOGO_Y,LOGO_W,LOGO_H);
      } catch(e) {
        doc.setTextColor(245,158,11); doc.setFontSize(14); doc.setFont("helvetica","bold");
        doc.text("AGBC",LOGO_X+2,HDR_H/2+4);
      }
      doc.setTextColor(255,255,255); doc.setFontSize(10); doc.setFont("helvetica","bold");
      doc.text("PROJECT PROGRESS REPORT",pageW-MARGIN,HDR_H/2-4,{align:"right"});
      doc.setFontSize(6.5); doc.setFont("helvetica","normal"); doc.setTextColor(160,160,160);
      doc.text(now,pageW-MARGIN,HDR_H-5,{align:"right"});
    };

    drawHeader();
    let y = HDR_H + 8;

    // ── Project title block
    doc.setFillColor(248,250,252); doc.setDrawColor(226,232,240); doc.setLineWidth(0.3);
    doc.roundedRect(MARGIN,y,usableW,22,2,2,"FD");
    doc.setTextColor(245,158,11); doc.setFontSize(8); doc.setFont("helvetica","bold");
    doc.text(sel.number||"",MARGIN+4,y+7);
    doc.setTextColor(30,41,59); doc.setFontSize(13);
    doc.text(sel.name||"",MARGIN+4,y+16);
    const SC={"Active":[16,185,129],"Completed":[59,130,246],"On Hold":[245,158,11],"Cancelled":[239,68,68]};
    const sc=SC[sel.status]||[148,163,184];
    doc.setFillColor(...sc); doc.roundedRect(pageW-MARGIN-28,y+7,25,8,2,2,"F");
    doc.setTextColor(255,255,255); doc.setFontSize(7); doc.setFont("helvetica","bold");
    doc.text(sel.status||"—",pageW-MARGIN-15.5,y+13,{align:"center"});
    y+=27;

    // ── Project info grid
    doc.setFontSize(8.5); doc.setFont("helvetica","bold"); doc.setTextColor(100,116,139);
    doc.text("PROJECT DETAILS",MARGIN,y+4);
    doc.setDrawColor(245,158,11); doc.setLineWidth(0.4);
    doc.line(MARGIN,y+5.5,MARGIN+36,y+5.5);
    y+=10;
    const INFO=[
      ["Project No.",    sel.number||"—"],
      ["Location",       sel.location||"—"],
      ["Duration",       sel.duration?sel.duration+" Months":"—"],
      ["Plot Area",      sel.plotArea?sel.plotArea+" sqft":"—"],
      ["BUA",            sel.bua?sel.bua+" sqft":"—"],
      ["Start Date",     sel.startDate||"—"],
      ["End Date",       sel.endDate||"—"],
      ["Consultant",     sel.consultant||"—"],
      ["Consultant Tel", sel.consultantContact||"—"],
      ["Status",         sel.status||"—"],
    ];
    const colW = (usableW-4)/2;
    INFO.forEach(([lbl,val],idx)=>{
      const cx=MARGIN+(idx%2)*(colW+4);
      const cy=y+Math.floor(idx/2)*11;
      doc.setFontSize(6); doc.setFont("helvetica","normal"); doc.setTextColor(148,163,184);
      doc.text(lbl,cx,cy);
      doc.setFontSize(7.5); doc.setFont("helvetica","bold"); doc.setTextColor(30,41,59);
      doc.text(String(val).substring(0,42),cx,cy+5.5);
    });
    y+=Math.ceil(INFO.length/2)*11+6;

    // ── KPI boxes
    doc.setFontSize(8.5); doc.setFont("helvetica","bold"); doc.setTextColor(100,116,139);
    doc.text("PROGRESS OVERVIEW",MARGIN,y+4);
    doc.setDrawColor(245,158,11); doc.line(MARGIN,y+5.5,MARGIN+43,y+5.5);
    y+=10;
    const comp=pgItems.filter(i=>i.status==="Completed").length;
    const inp=pgItems.filter(i=>i.status==="In Progress").length;
    const nst=pgItems.filter(i=>i.status==="Not Started").length;
    const ohd=pgItems.filter(i=>i.status==="On Hold").length;
    const KPIS=[
      {l:"Overall",     v:overallPct+"%",   c:[59,130,246]},
      {l:"Total",       v:pgItems.length,   c:[100,116,139]},
      {l:"Completed",   v:comp,             c:[16,185,129]},
      {l:"In Progress", v:inp,              c:[245,158,11]},
      {l:"Not Started", v:nst,              c:[239,68,68]},
      {l:"On Hold",     v:ohd,              c:[168,85,247]},
    ];
    const kw=(usableW-2*(KPIS.length-1))/KPIS.length;
    KPIS.forEach((k,i)=>{
      const kx=MARGIN+i*(kw+2);
      doc.setFillColor(...k.c); doc.roundedRect(kx,y,kw,18,2,2,"F");
      doc.setTextColor(255,255,255); doc.setFontSize(14); doc.setFont("helvetica","bold");
      doc.text(String(k.v),kx+kw/2,y+12,{align:"center"});
      doc.setFontSize(5.5); doc.setFont("helvetica","normal");
      doc.text(k.l,kx+kw/2,y+17,{align:"center"});
    });
    y+=23;

    // ── Overall progress bar
    doc.setFillColor(241,245,249); doc.roundedRect(MARGIN,y,usableW,8,2,2,"F");
    const fill=Math.max(0.5,(overallPct/100)*usableW);
    const barClr=overallPct>=80?[16,185,129]:overallPct>=50?[59,130,246]:overallPct>=25?[245,158,11]:[239,68,68];
    doc.setFillColor(...barClr); doc.roundedRect(MARGIN,y,fill,8,2,2,"F");
    doc.setTextColor(overallPct>45?255:30,overallPct>45?255:41,overallPct>45?255:59);
    doc.setFontSize(6); doc.setFont("helvetica","bold");
    doc.text(overallPct+"% Complete · "+comp+" of "+pgItems.length+" activities done",MARGIN+usableW/2,y+5.5,{align:"center"});
    y+=14;

    // ── CHART 1: Horizontal Work Done% vs Remaining% bars ────────────────────
    if(pgItems.length>0){
      // Check space — add page if less than 40mm left
      if(y+pgItems.length*7.5+14 > pageH-16){ doc.addPage(); drawHeader(); y=HDR_H+8; }

      doc.setFontSize(8.5); doc.setFont("helvetica","bold"); doc.setTextColor(100,116,139);
      doc.text("WORK DONE % vs REMAINING % PER ACTIVITY",MARGIN,y+4);
      doc.setDrawColor(245,158,11); doc.setLineWidth(0.4);
      doc.line(MARGIN,y+5.5,MARGIN+75,y+5.5);
      y+=10;

      const LBL_W   = 42;
      const BAR_H   = 5.5;
      const BAR_GAP = 2;
      const BAR_AREA = usableW - LBL_W - 14;

      pgItems.forEach((pg,idx)=>{
        const lbl=(pg.activity==="Other (Custom)"&&pg.customActivity)?pg.customActivity:(pg.activity||"—");
        const pct=Math.min(100,Math.max(0,Number(pg.pct)||0));
        const by =y+idx*(BAR_H+BAR_GAP);
        if(by+BAR_H>pageH-14) return; // skip overflow rows

        // Label
        doc.setFontSize(5.8); doc.setFont("helvetica","normal"); doc.setTextColor(30,41,59);
        doc.text(lbl.substring(0,25),MARGIN,by+BAR_H-1.2);

        // Background bar (remaining)
        doc.setFillColor(241,245,249);
        doc.roundedRect(MARGIN+LBL_W,by,BAR_AREA,BAR_H,1,1,"F");

        // Done portion
        const doneW=(pct/100)*BAR_AREA;
        if(doneW>=1){
          const clr=pct>=100?[16,185,129]:pct>=60?[59,130,246]:pct>=30?[245,158,11]:[239,68,68];
          doc.setFillColor(...clr);
          doc.roundedRect(MARGIN+LBL_W,by,doneW,BAR_H,1,1,"F");
        }

        // % labels
        doc.setFontSize(5); doc.setFont("helvetica","bold");
        if(doneW>10){ doc.setTextColor(255,255,255); doc.text(pct+"%",MARGIN+LBL_W+doneW-2,by+BAR_H-1.2,{align:"right"}); }
        else if(pct>0){ doc.setTextColor(80,80,80); doc.text(pct+"%",MARGIN+LBL_W+doneW+2,by+BAR_H-1.2); }
        doc.setFontSize(5); doc.setTextColor(148,163,184);
        doc.text((100-pct)+"%",MARGIN+LBL_W+BAR_AREA+2,by+BAR_H-1.2);

        // Status dot
        const SDC={"Completed":[16,185,129],"In Progress":[59,130,246],"On Hold":[245,158,11],"Not Started":[239,68,68]};
        const dc=SDC[pg.status]||[148,163,184];
        doc.setFillColor(...dc); doc.circle(MARGIN+LBL_W+BAR_AREA+11,by+BAR_H/2,1.5,"F");
      });

      y += pgItems.length*(BAR_H+BAR_GAP)+6;
    }

    // ── CHART 2: Vertical grouped bars — Actual vs Done vs Balance (qty items only) ──
    // Show chart for ALL activities — qty-based or pct-based
    const qtyPg=pgItems; // Show ALL activities in chart
    if(qtyPg.length>0){
      const CHART_H=50;
      if(y+CHART_H+26>pageH-16){ doc.addPage(); drawHeader(); y=HDR_H+8; }

      doc.setFontSize(8.5); doc.setFont("helvetica","bold"); doc.setTextColor(100,116,139);
      doc.text("QUANTITY PROGRESS — ACTUAL vs WORK DONE vs BALANCE",MARGIN,y+4);
      doc.setDrawColor(245,158,11); doc.setLineWidth(0.4);
      doc.line(MARGIN,y+5.5,MARGIN+80,y+5.5);
      y+=10;

      const hasAnyQty=qtyPg.some(i=>(Number(i.actualQty)||0)>0);
      const maxQty=hasAnyQty?Math.max(...qtyPg.map(i=>Number(i.actualQty)||0),1):100;
      const actW=usableW/qtyPg.length;
      const barW=Math.min(Math.max((actW-6)/3,2),10);
      const chartTop=y;

      // Grid lines + Y labels
      [0,25,50,75,100].forEach(pctG=>{
        const gy=chartTop+CHART_H-(pctG/100)*CHART_H;
        doc.setDrawColor(235,235,235); doc.setLineWidth(0.15);
        doc.line(MARGIN,gy,MARGIN+usableW,gy);
        if(pctG>0){
          doc.setFontSize(4.5); doc.setFont("helvetica","normal"); doc.setTextColor(200,200,200);
          doc.text(String(Math.round((pctG/100)*maxQty)),MARGIN-1,gy+1,{align:"right"});
        }
      });

      // X-axis
      doc.setDrawColor(200,200,200); doc.setLineWidth(0.3);
      doc.line(MARGIN,chartTop+CHART_H,MARGIN+usableW,chartTop+CHART_H);

      qtyPg.forEach((pg,i)=>{
        const cx=MARGIN+i*actW+actW/2;
        const hasQty=(Number(pg.actualQty)||0)>0;
        // Use qty if available, else use pct-based (100 = full bar)
        const actual=hasQty?Number(pg.actualQty):100;
        const done  =hasQty?Number(pg.workDoneQty):(Number(pg.pct)||0);
        const bal   =hasQty?Number(pg.balanceQty):(100-(Number(pg.pct)||0));
        const _max  =hasQty?maxQty:100;
        const actualH=(actual/_max)*CHART_H;
        const doneH  =(done/_max)*CHART_H;
        const balH   =(bal/_max)*CHART_H;

        // Actual (blue)
        if(actualH>0){ doc.setFillColor(59,130,246); doc.rect(cx-barW*1.6,chartTop+CHART_H-actualH,barW,actualH,"F"); }
        // Done (green)
        if(doneH>0){   doc.setFillColor(16,185,129); doc.rect(cx-barW*0.5,chartTop+CHART_H-doneH,barW,doneH,"F"); }
        // Balance (red)
        if(balH>0){    doc.setFillColor(239,68,68);  doc.rect(cx+barW*0.6,chartTop+CHART_H-balH,barW,balH,"F"); }

        // Value labels above bars
        doc.setFontSize(4.5); doc.setFont("helvetica","bold");
        const aLbl=hasQty?String(actual):actual+"%";
        const dLbl=hasQty?String(done):done+"%";
        const bLbl=hasQty?String(bal):bal+"%";
        if(actualH>5){ doc.setTextColor(59,130,246); doc.text(aLbl,cx-barW*1.6+barW/2,chartTop+CHART_H-actualH-1,{align:"center"}); }
        if(doneH>5){   doc.setTextColor(16,185,129); doc.text(dLbl,cx-barW*0.5+barW/2,chartTop+CHART_H-doneH-1,{align:"center"}); }
        if(balH>5){    doc.setTextColor(239,68,68);  doc.text(bLbl,cx+barW*0.6+barW/2,chartTop+CHART_H-balH-1,{align:"center"}); }

        // Activity name + unit below axis
        const lbl=(pg.activity==="Other (Custom)"&&pg.customActivity)?pg.customActivity:(pg.activity||"—");
        const shortLbl=lbl.length>9?lbl.substring(0,9)+"…":lbl;
        doc.setFontSize(5); doc.setFont("helvetica","normal"); doc.setTextColor(100,116,139);
        doc.text(shortLbl,cx,chartTop+CHART_H+5,{align:"center"});
        doc.setFontSize(4.5); doc.setTextColor(180,180,180);
        doc.text(pg.unit||"NOS",cx,chartTop+CHART_H+9.5,{align:"center"});
      });

      // Legend
      const legY=chartTop+CHART_H+14;
      [[59,130,246,"Actual Qty"],[16,185,129,"Work Done"],[239,68,68,"Balance"]].forEach(([r,g,b,lbl],i)=>{
        doc.setFillColor(r,g,b); doc.rect(MARGIN+i*34,legY,4,3,"F");
        doc.setFontSize(6); doc.setFont("helvetica","normal"); doc.setTextColor(80,80,80);
        doc.text(lbl,MARGIN+i*34+5.5,legY+3);
      });
      y=legY+10;
    }

    // ── Totals row for qty-based activities
    const qtyItems=pgItems.filter(i=>i.unit!=="Lumpsum"&&(Number(i.actualQty)||0)>0);
    if(qtyItems.length>0){
      const totA=qtyItems.reduce((s,i)=>s+(Number(i.actualQty)||0),0);
      const totD=qtyItems.reduce((s,i)=>s+(Number(i.workDoneQty)||0),0);
      const totB=qtyItems.reduce((s,i)=>s+(Number(i.balanceQty)||0),0);
      doc.setFillColor(254,252,232); doc.setDrawColor(253,230,138); doc.setLineWidth(0.3);
      doc.roundedRect(MARGIN,y,usableW,9,1,1,"FD");
      doc.setTextColor(92,67,7); doc.setFontSize(6.5); doc.setFont("helvetica","bold");
      doc.text(`Qty Summary (excl. Lumpsum):  Actual Total: ${totA.toLocaleString()}   Work Done: ${totD.toLocaleString()}   Balance: ${totB.toLocaleString()}`,MARGIN+3,y+6);
      y+=13;
    }

    // ── Activities section header
    doc.setFontSize(8.5); doc.setFont("helvetica","bold"); doc.setTextColor(100,116,139);
    doc.text("ACTIVITY PROGRESS DETAILS",MARGIN,y+4);
    doc.setDrawColor(245,158,11); doc.line(MARGIN,y+5.5,MARGIN+56,y+5.5);
    y+=10;

    if(pgItems.length===0){
      doc.setFontSize(8); doc.setTextColor(148,163,184); doc.setFont("helvetica","italic");
      doc.text("No activities recorded for this project.",MARGIN,y+8);
    } else {
      const heads=[[
        "#","Activity","Unit","Actual Qty","Work Done","Balance","Progress %","Status","Pln.Start","Pln.End","Remarks"
      ]];
      const rows=pgItems.map((pg,idx)=>{
        const lbl=(pg.activity==="Other (Custom)"&&pg.customActivity)?pg.customActivity:(pg.activity||pg.customActivity||"—");
        const isL=pg.unit==="Lumpsum";
        return[
          String(idx+1),
          lbl.substring(0,30),
          pg.unit||"NOS",
          isL?"L/S":String(pg.actualQty||0),
          isL?(pg.pct||0)+"%":String(pg.workDoneQty||0),
          isL?(100-(pg.pct||0))+"%":String(pg.balanceQty||0),
          (pg.pct||0)+"%",
          pg.status||"—",
          pg.plannedStart||"—",
          pg.plannedEnd||"—",
          (pg.remarks||"").substring(0,30),
        ];
      });
      doc.autoTable({
        startY:y, margin:{left:MARGIN,right:MARGIN,bottom:16},
        head:heads, body:rows, theme:"grid",
        styles:{fontSize:6.2,cellPadding:2.2,overflow:"linebreak",valign:"middle",textColor:[30,41,59],lineColor:[220,220,220],lineWidth:0.2},
        headStyles:{fillColor:[30,41,59],textColor:[255,255,255],fontStyle:"bold",fontSize:6.5,halign:"center",cellPadding:3},
        alternateRowStyles:{fillColor:[248,250,252]},
        columnStyles:{
          0:{cellWidth:7,halign:"center"},
          1:{cellWidth:36},
          2:{cellWidth:13,halign:"center"},
          3:{cellWidth:15,halign:"center"},
          4:{cellWidth:15,halign:"center"},
          5:{cellWidth:15,halign:"center"},
          6:{cellWidth:16,halign:"center"},
          7:{cellWidth:18,halign:"center"},
          8:{cellWidth:16,halign:"center"},
          9:{cellWidth:16,halign:"center"},
          10:{cellWidth:20},
        },
        didParseCell:(data)=>{
          if(data.section==="body"){
            if(data.column.index===6){
              const p=parseInt(data.cell.text[0])||0;
              data.cell.styles.textColor=p>=100?[16,185,129]:p>=60?[59,130,246]:p>=30?[245,158,11]:[239,68,68];
              data.cell.styles.fontStyle="bold";
            }
            if(data.column.index===7){
              const s=data.cell.text[0];
              data.cell.styles.textColor=s==="Completed"?[16,185,129]:s==="In Progress"?[59,130,246]:s==="On Hold"?[245,158,11]:[239,68,68];
              data.cell.styles.fontStyle="bold";
            }
          }
        },
        didDrawPage:({pageNumber})=>{
          if(pageNumber>1) drawHeader();
          const tot=doc.internal.getNumberOfPages();
          doc.setFontSize(7); doc.setTextColor(160); doc.setFont("helvetica","normal");
          doc.text(`Page ${pageNumber} / ${tot}  ·  Generated: ${now}`,pageW/2,pageH-5,{align:"center"});
        },
      });
    }


    // ── Progress Photos ──────────────────────────────────────────────────────
    if(projPhotos && projPhotos.length>0){
      doc.addPage(); drawHeader();
      let py=HDR_H+8;
      doc.setFontSize(8.5);doc.setFont("helvetica","bold");doc.setTextColor(100,116,139);
      doc.text("PROGRESS PHOTOS ("+projPhotos.length+" photo"+(projPhotos.length>1?"s":"")+")",MARGIN,py+4);
      doc.setDrawColor(245,158,11);doc.setLineWidth(0.4);
      doc.line(MARGIN,py+5.5,MARGIN+55,py+5.5);
      py+=12;
      const IMG_W=(usableW-6)/2, IMG_H=52;
      let pcol=0,prow=0;
      const _WRKR=(process.env.REACT_APP_R2_WORKER_URL||"").replace(/\/$/,"");

      // Get image as base64 data URL
      // Supabase Storage URLs: fetch directly (CORS supported)
      // R2 URLs: use Worker proxy
      const toB64=async(url)=>{
        try{
          const isSupabase=url.includes("supabase.co/storage");
          const _fn=url.split("/").pop().split("?")[0];
          const proxyUrl=isSupabase?url:(_WRKR?`${_WRKR}/file/${encodeURIComponent(_fn)}`:url);
          const resp=await fetch(proxyUrl,{mode:"cors"});
          if(!resp.ok) throw new Error("HTTP "+resp.status);
          const blob=await resp.blob();
          return await new Promise((resolve,reject)=>{
            const reader=new FileReader();
            reader.onloadend=()=>resolve(reader.result);
            reader.onerror=reject;
            reader.readAsDataURL(blob);
          });
        }catch(err){
          console.warn("Photo fetch failed:",err.message);
          return null;
        }
      };

      // Detect image format from data URL
      const getImgFmt=(b64)=>{
        if(!b64) return "JPEG";
        if(b64.startsWith("data:image/png")) return "PNG";
        if(b64.startsWith("data:image/webp")) return "WEBP";
        if(b64.startsWith("data:image/gif")) return "GIF";
        return "JPEG";
      };

      for(const ph of projPhotos.slice(0,12)){
        const checkY=py+prow*(IMG_H+18);
        if(checkY+IMG_H+18>pageH-14){doc.addPage();drawHeader();py=HDR_H+8;prow=0;pcol=0;}
        const ix=MARGIN+pcol*(IMG_W+6);
        const iy=py+prow*(IMG_H+18);

        // Photo frame
        doc.setFillColor(240,240,240);
        doc.rect(ix,iy,IMG_W,IMG_H,"F");
        doc.setDrawColor(200,200,200);doc.setLineWidth(0.3);
        doc.rect(ix,iy,IMG_W,IMG_H);

        if(ph.file_url){
          const b64=await toB64(ph.file_url);
          if(b64 && b64.length>200){
            try{
              const fmt=getImgFmt(b64);
              doc.addImage(b64,fmt,ix,iy,IMG_W,IMG_H,"","FAST");
            }catch(imgErr){
              console.warn("addImage failed:",imgErr.message);
              doc.setFontSize(6);doc.setTextColor(150,150,150);
              doc.text("Image format error",ix+IMG_W/2,iy+IMG_H/2,{align:"center"});
            }
          }else{
            doc.setFontSize(6);doc.setTextColor(150,150,150);
            doc.text("Photo unavailable",ix+IMG_W/2,iy+IMG_H/2,{align:"center"});
          }
        }

        // Caption box below image
        doc.setFillColor(248,250,252);doc.setDrawColor(226,232,240);doc.setLineWidth(0.2);
        doc.rect(ix,iy+IMG_H,IMG_W,15,"FD");
        doc.setFontSize(6.2);doc.setFont("helvetica","bold");doc.setTextColor(30,41,59);
        doc.text((ph.caption||"No caption").substring(0,32),ix+2,iy+IMG_H+6);
        doc.setFontSize(5.5);doc.setFont("helvetica","normal");doc.setTextColor(148,163,184);
        const meta=[ph.photo_date,ph.area].filter(Boolean).join(" · ");
        doc.text(meta.substring(0,38),ix+2,iy+IMG_H+12);
        pcol++;if(pcol>=2){pcol=0;prow++;}
      }
    }

    doc.save(`Project_Report_${sel.number}_${today}.pdf`);
  } catch(e){ console.error("Project PDF error:",e); alert("Export failed: "+e.message); }
};

