// ── useManpowerMaster Hook ────────────────────────────────────────────────────


// ── DPR Manpower Section — Drop-in replacement for manpower rows in DPR form ──
// Use this inside your DPR form where subcontractor manpower is entered

const DPRManpowerSection = ({ subcontractorId, subcontractorName, dprId, reportDate, projectId, showToast }) => {
  const [rows,    setRows]    = useState([]);
  const [loading, setLoading] = useState(false);
  const [saving,  setSaving]  = useState(false);
  const [saved,   setSaved]   = useState(false);

  const AM_OPTS = ["P","A","H"];
  const PM_OPTS = ["P","A","H"];

  // Load active manpower for this subcontractor
  useEffect(() => {
    if (!subcontractorId) { setRows([]); return; }
    const load = async () => {
      setLoading(true);

      // Check if attendance already saved for this DPR+subcontractor
      if (dprId) {
        const { data: existing } = await supabase
          .from("dpr_attendance")
          .select("*, manpower_master(*)")
          .eq("dpr_id", dprId)
          .eq("subcontractor_id", subcontractorId);

        if (existing && existing.length > 0) {
          setRows(existing.map(a => ({
            attId:       a.id,
            masterId:    a.manpower_master_id,
            empId:       a.manpower_master?.employee_id       || "",
            name:        a.manpower_master?.employee_name     || "",
            designation: a.manpower_master?.designation       || "",
            teamNo:      a.team_no || a.manpower_master?.default_team_no || "",
            am:          a.am_status    || "P",
            pm:          a.pm_status    || "P",
            ot:          a.ot_hours     || 0,
            work:        a.description_of_work || "",
            remarks:     a.daily_remarks || "",
            saved:       true,
          })));
          setSaved(true);
          setLoading(false);
          return;
        }
      }

      // Load fresh from master
      const { data: mpData } = await supabase
        .from("manpower_master")
        .select("*")
        .eq("subcontractor_id", subcontractorId)
        .eq("status", "Active")
        .order("employee_name");

      if (mpData) {
        setRows(mpData.map(m => ({
          attId:       null,
          masterId:    m.id,
          empId:       m.employee_id   || "",
          name:        m.employee_name || "",
          designation: m.designation   || m.trade || "",
          teamNo:      m.default_team_no || "",
          am:    "P",
          pm:    "P",
          ot:    0,
          work:  "",
          remarks: "",
          saved: false,
        })));
      }
      setLoading(false);
    };
    load();
  }, [subcontractorId, dprId]);

  const setRow = (idx, k, v) => setRows(p => p.map((r,i) => i===idx ? {...r,[k]:v} : r));

  const presentAM = rows.filter(r => r.am === "P").length;
  const presentPM = rows.filter(r => r.pm === "P").length;

  const handleSave = async () => {
    if (!dprId) { showToast("Save DPR first before saving attendance","error"); return; }
    setSaving(true);
    let errors = 0;
    for (const row of rows) {
      if (!row.masterId) continue;
      const payload = {
        dpr_id:              dprId,
        subcontractor_id:    subcontractorId,
        manpower_master_id:  row.masterId,
        project_id:          projectId || null,
        report_date:         reportDate || null,
        am_status:           row.am,
        pm_status:           row.pm,
        ot_hours:            Number(row.ot) || 0,
        description_of_work: row.work,
        team_no:             row.teamNo,
        daily_remarks:       row.remarks,
      };
      if (row.attId) {
        const { error } = await supabase.from("dpr_attendance").update(payload).eq("id", row.attId);
        if (error) errors++;
      } else {
        const { data, error } = await supabase.from("dpr_attendance").insert([payload]).select().single();
        if (error) errors++;
        else {
          setRows(p => p.map(r => r.masterId===row.masterId ? {...r, attId:data.id, saved:true} : r));
        }
      }
    }
    setSaving(false);
    if (errors > 0) showToast(`${errors} rows failed to save`, "error");
    else { showToast("✅ Attendance saved!"); setSaved(true); }
  };

  if (loading) return <div className="text-xs text-slate-400 py-4 text-center">Loading manpower...</div>;
  if (rows.length === 0) return (
    <div className="bg-amber-50 border border-amber-200 rounded-xl p-4 text-xs text-amber-800 text-center">
      No active employees in master for this subcontractor.
      <span className="block mt-1 font-semibold">Go to Manpower Master → Add employees first.</span>
    </div>
  );

  return (
    <div className="mt-3">
      {/* Summary bar */}
      <div className="flex flex-wrap gap-3 mb-2">
        <span className="text-xs bg-green-100 text-green-700 px-3 py-1 rounded-full font-semibold border border-green-200">
          AM Present: {presentAM} / {rows.length}
        </span>
        <span className="text-xs bg-blue-100 text-blue-700 px-3 py-1 rounded-full font-semibold border border-blue-200">
          PM Present: {presentPM} / {rows.length}
        </span>
        <span className="text-xs bg-amber-100 text-amber-700 px-3 py-1 rounded-full font-semibold border border-amber-200">
          Total: {rows.length} Workers
        </span>
        {saved && <span className="text-xs bg-slate-100 text-slate-500 px-3 py-1 rounded-full font-semibold border border-slate-200">✅ Saved</span>}
      </div>

      {/* Table */}
      <div className="overflow-x-auto rounded-xl border border-slate-200">
        <table className="w-full text-xs min-w-[800px]">
          <thead className="bg-slate-700 text-white">
            <tr>{["S.No","Emp ID","Name","Designation","A.M","P.M","O.T Hrs","Description of Work","Team No","Remarks"].map(h => (
              <th key={h} className="px-2 py-2 text-left font-semibold whitespace-nowrap">{h}</th>
            ))}</tr>
          </thead>
          <tbody>
            {rows.map((r, idx) => (
              <tr key={idx} className={`border-t border-slate-100 ${idx%2===0?"bg-white":"bg-slate-50/50"}`}>
                <td className="px-2 py-1.5 text-slate-400 text-center">{idx+1}</td>
                <td className="px-2 py-1.5 font-mono text-slate-600">{r.empId||"—"}</td>
                <td className="px-2 py-1.5 font-semibold text-slate-800 whitespace-nowrap">{r.name}</td>
                <td className="px-2 py-1.5 text-slate-600">{r.designation||"—"}</td>
                <td className="px-1 py-1 w-16">
                  <select value={r.am} onChange={e=>setRow(idx,"am",e.target.value)}
                    className={`w-full text-xs px-1 py-1 rounded border font-bold text-center
                      ${r.am==="P"?"bg-green-100 text-green-700 border-green-300"
                        :r.am==="A"?"bg-red-100 text-red-700 border-red-300"
                        :"bg-amber-100 text-amber-700 border-amber-300"}`}>
                    {AM_OPTS.map(o=><option key={o}>{o}</option>)}
                  </select>
                </td>
                <td className="px-1 py-1 w-16">
                  <select value={r.pm} onChange={e=>setRow(idx,"pm",e.target.value)}
                    className={`w-full text-xs px-1 py-1 rounded border font-bold text-center
                      ${r.pm==="P"?"bg-green-100 text-green-700 border-green-300"
                        :r.pm==="A"?"bg-red-100 text-red-700 border-red-300"
                        :"bg-amber-100 text-amber-700 border-amber-300"}`}>
                    {PM_OPTS.map(o=><option key={o}>{o}</option>)}
                  </select>
                </td>
                <td className="px-1 py-1 w-14">
                  <input type="number" value={r.ot||""} min="0" max="12" step="0.5"
                    onChange={e=>setRow(idx,"ot",e.target.value)}
                    className="w-full text-xs px-1.5 py-1 rounded border border-slate-200 text-center focus:outline-none focus:ring-1 focus:ring-amber-400"/>
                </td>
                <td className="px-1 py-1 min-w-[140px]">
                  <input value={r.work||""} onChange={e=>setRow(idx,"work",e.target.value)}
                    placeholder="Work done..."
                    className="w-full text-xs px-1.5 py-1 rounded border border-slate-200 focus:outline-none focus:ring-1 focus:ring-amber-400"/>
                </td>
                <td className="px-1 py-1 w-16">
                  <input value={r.teamNo||""} onChange={e=>setRow(idx,"teamNo",e.target.value)}
                    placeholder="T-01"
                    className="w-full text-xs px-1.5 py-1 rounded border border-slate-200 text-center focus:outline-none focus:ring-1 focus:ring-amber-400"/>
                </td>
                <td className="px-1 py-1 min-w-[100px]">
                  <input value={r.remarks||""} onChange={e=>setRow(idx,"remarks",e.target.value)}
                    placeholder="Notes..."
                    className="w-full text-xs px-1.5 py-1 rounded border border-slate-200 focus:outline-none focus:ring-1 focus:ring-amber-400"/>
                </td>
              </tr>
            ))}
          </tbody>
          <tfoot className="bg-slate-50 border-t-2 border-slate-300">
            <tr>
              <td colSpan={4} className="px-3 py-2 text-xs font-bold text-slate-700">
                TOTAL — {subcontractorName}
              </td>
              <td className="px-2 py-2 text-center">
                <span className="text-xs font-bold text-green-700 bg-green-100 px-2 py-0.5 rounded-full">{presentAM}P</span>
              </td>
              <td className="px-2 py-2 text-center">
                <span className="text-xs font-bold text-blue-700 bg-blue-100 px-2 py-0.5 rounded-full">{presentPM}P</span>
              </td>
              <td className="px-2 py-2 text-center text-xs font-bold text-amber-700">
                {rows.reduce((s,r)=>s+(Number(r.ot)||0),0)}h
              </td>
              <td colSpan={3}/>
            </tr>
          </tfoot>
        </table>
      </div>

      <div className="flex justify-end mt-3">
        <button onClick={handleSave} disabled={saving}
          className="text-sm bg-green-600 hover:bg-green-700 text-white font-semibold px-4 py-2 rounded-lg disabled:opacity-50 flex items-center gap-2">
          {saving ? "Saving..." : "💾 Save Attendance"}
        </button>
      </div>
    </div>
  );
};


export default function App() {
  const { user, loading: authLoading } = useAuth();
  const { projects, loading: plLoad, add: addP, update: updP, remove: delP } = useProjects();
  const { tasks, loading: tlLoad, add: addT, update: updT, remove: delT } = useTasks();
  const { snags, loading: slLoad, add: addS, update: updS, remove: delS } = useSnags();
  const { reports, loading: rlLoad, add: addR, update: updR, remove: delR } = useDailyReports();
  const { inspections, loading: ilLoad, add: addI, update: updI, remove: delI } = useInspections();
  const { drawings, loading: dlLoad, add: addD, update: updD, remove: delD } = useDrawings();
  const { subs, loading: sbLoad, add: addSub, update: updSub, remove: delSub } = useSubcontractors();
  const { progressItems, add: addPg, update: updPg, remove: delPg } = useProjectProgress();

  // App-level overall progress calculator — used by Dashboard + Projects card
  const getOverallPct = (pid) => {
    const items = progressItems.filter(p => p.pid === pid);
    if (!items.length) return 0;
    const withQty = items.filter(i => i.unit !== "Lumpsum" && (Number(i.actualQty)||0) > 0);
    if (withQty.length > 0) {
      const totalActual = withQty.reduce((s,i) => s + (Number(i.actualQty)||0), 0);
      const totalDone   = withQty.reduce((s,i) => s + (Number(i.workDoneQty)||0), 0);
      const qtyPct      = totalActual > 0 ? Math.round((totalDone / totalActual) * 100) : 0;
      const lumpItems   = items.filter(i => i.unit === "Lumpsum" || (Number(i.actualQty)||0) === 0);
      const lumpAvg     = lumpItems.length > 0 ? lumpItems.reduce((s,i) => s + (Number(i.pct)||0), 0) / lumpItems.length : null;
      if (lumpAvg !== null) return Math.round((qtyPct + lumpAvg) / 2);
      return Math.min(100, qtyPct);
    }
    return Math.round(items.reduce((a,i) => a + (Number(i.pct)||0), 0) / items.length);
  };

  // Enrich projects array with live overallPct — auto-updates when progressItems changes
  const projectsWithPct = projects.map(p => ({ ...p, overallPct: getOverallPct(p.id) }));
  const { photos, loading: phLoad, add: addPh, update: updPh, remove: delPh } = usePhotos();
  const { users,  loading: usLoad,  add: addU,   update: updU,  remove: delU  } = useUsers();
  const { mrs, loading: mrLoad, add: addMr, update: updMr, remove: delMr, updateStatus: updMrStatus } = useMatReqs();
  const { lpos, loading: lpoLoad, add: addLpo, update: updLpo, remove: delLpo } = useLPOs();
  const { stock, receipts, issues, loading: stLoad, addStock, updateStock, removeStock, addReceipt, approveReceipt, removeReceipt, addIssue, removeIssue } = useStore();
  const { nocs, loading: nocLoad, add: addNoc, update: updNoc, remove: delNoc } = useNOCs();
  const { masters: mpMasters, loadAttendance, saveAttendance } = useManpowerMaster();
  const [prefillMr, setPrefillMr] = useState(null);

  const { profile: userProfile } = useUserProfile(user);
  const { reqs: permReqs, addReq: addPermReq, updateReq: updatePermReq } = usePermRequests();
  const userCanEdit = canEdit(userProfile);
  const userIsAdmin = isAdmin(userProfile);
  const { notifs, unreadCount, markRead, markAllRead, deleteNotif, generateNotifs } = useNotifications();
  const { toast, showToast, hideToast } = useToast();
  const [page, setPage] = useState("dashboard");
  const [navFilter, setNavFilter] = useState({});
  // navigate(page, filterObj) — used by dashboard cards and alerts
  const navigate = (pg, filter = {}) => { setPage(pg); setNavFilter(filter); };

  // Auto-generate notifications whenever live data changes (lengths used intentionally)
  useEffect(() => { // eslint-disable-line react-hooks/exhaustive-deps
    if (tasks.length || snags.length || mrs.length || lpos.length || nocs.length) {
      generateNotifs({ tasks, snags, inspections, mrs, lpos, drawings, nocs });
    }
  }, [tasks.length, snags.length, inspections.length, mrs.length, lpos.length, drawings.length, nocs.length]); // eslint-disable-line
  const [collapsed, setCollapsed] = useState(false);
  const [mobileOpen, setMobileOpen] = useState(false);

  if (authLoading) return (
    <div className="flex h-screen items-center justify-center bg-slate-50">
      <div className="text-center space-y-3">
        <div className="w-12 h-12 border-4 border-amber-400 border-t-transparent rounded-full animate-spin mx-auto"></div>
        <p className="text-sm text-slate-500 font-medium">Loading AGBC...</p>
      </div>
    </div>
  );

  if (!user) return <Login onLogin={() => {}} />;

  const pp = { projects: projectsWithPct, photos, showToast, userProfile, userCanEdit, userIsAdmin, permReqs, onAddPermReq: addPermReq, navFilter, onNavigate: navigate };

  const renderPage = () => {
    switch (page) {
      case "dashboard":      return <Dashboard projects={projectsWithPct} tasks={tasks} snags={snags} inspections={inspections} reports={reports} mrs={mrs} lpos={lpos} stock={stock} nocs={nocs} onNavigate={navigate}/>;
      case "projects":       return <Projects {...pp} projects={projectsWithPct} loading={plLoad} onAdd={addP} onUpdate={updP} onDelete={delP} progressItems={progressItems} onAddPg={addPg} onUpdatePg={updPg} onDeletePg={delPg} />;
      case "tasks":          return <Tasks {...pp} tasks={tasks} loading={tlLoad} onAdd={addT} onUpdate={updT} onDelete={delT} />;
      case "snags":          return <Snags {...pp} snags={snags} loading={slLoad} onAdd={addS} onUpdate={updS} onDelete={delS} />;
      case "reports":        return <DailyReports subcontractors={subs} mpMasters={mpMasters} loadAttendance={loadAttendance} saveAttendance={saveAttendance} {...pp} reports={reports} loading={rlLoad} onAdd={addR} onUpdate={updR} onDelete={delR} />;
      case "inspections":    return <Inspections {...pp} inspections={inspections} loading={ilLoad} onAdd={addI} onUpdate={updI} onDelete={delI} />;
      case "drawings":       return <Drawings {...pp} drawings={drawings} loading={dlLoad} onAdd={addD} onUpdate={updD} onDelete={delD} />;
      case "photos":         return <Photos {...pp} photos={photos} loading={phLoad} onAdd={addPh} onUpdate={updPh} onDelete={delPh} />;
      case "subcontractors": return <Subcontractors subs={subs} loading={sbLoad} onAdd={addSub} onUpdate={updSub} onDelete={delSub} showToast={showToast} tasks={tasks} snags={snags} projects={projects} />;
      case "users":          return <Users users={users} usersLoading={usLoad} onAddUser={addU} onUpdateUser={updU} onDeleteUser={delU} projects={projects} showToast={showToast} userIsAdmin={userIsAdmin} userProfile={userProfile} permReqs={permReqs} onUpdatePermReq={updatePermReq}/>;
      case "mr":  return <MaterialRequests mrs={mrs} loading={mrLoad} onAdd={addMr} onUpdate={updMr} onDelete={delMr} onUpdateStatus={updMrStatus} projects={projects} showToast={showToast} onNavigateLpo={mr=>{setPrefillMr(mr);navigate("lpo");}}/>;
      case "lpo": return <LPOModule lpos={lpos} loading={lpoLoad} onAdd={addLpo} onUpdate={updLpo} onDelete={delLpo} projects={projects} mrs={mrs} showToast={showToast} prefillMr={prefillMr} onClearPrefill={()=>setPrefillMr(null)}/>;
      case "store": return <MaterialStore stock={stock} receipts={receipts} issues={issues} loading={stLoad} onAddStock={addStock} onUpdateStock={updateStock} onRemoveStock={removeStock} onAddReceipt={addReceipt} onApproveReceipt={approveReceipt} onRemoveReceipt={removeReceipt} onAddIssue={addIssue} onRemoveIssue={removeIssue} projects={projects} lpos={lpos} showToast={showToast}/>;
      case "noc":   return <NOCModule nocs={nocs} loading={nocLoad} onAdd={addNoc} onUpdate={updNoc} onDelete={delNoc} projects={projects} showToast={showToast}/>;
      case "manpower-master": return <ManpowerMaster subcontractors={subs} projects={projects} showToast={showToast}/>;
      default: return <div className="p-12 text-center text-slate-400 text-lg font-semibold">Module coming soon</div>;
    }
  };

  return (
    <div className="flex bg-slate-50 overflow-hidden font-sans text-slate-800 relative" style={{height:"100dvh"}}>
      <style>{`
        * { box-sizing: border-box; -webkit-tap-highlight-color: transparent; }
        html, body { margin: 0; height: 100%; overflow: hidden; }
        body { font-family: 'Inter', system-ui, -apple-system, sans-serif; }
        #root { height: 100%; }
        ::-webkit-scrollbar { width: 4px; height: 4px; }
        ::-webkit-scrollbar-track { background: #f1f5f9; }
        ::-webkit-scrollbar-thumb { background: #cbd5e1; border-radius: 99px; }
        .line-clamp-2 { display: -webkit-box; -webkit-line-clamp: 2; -webkit-box-orient: vertical; overflow: hidden; }
        /* All tables scroll horizontally on mobile */
        table { min-width: max-content; }
        .table-container { overflow-x: auto; -webkit-overflow-scrolling: touch; width: 100%; }
        /* Mobile global fixes */
        @media (max-width: 767px) {
          /* Reduce all padding on mobile */
          .p-6 { padding: 0.875rem !important; }
          .p-5 { padding: 0.75rem !important; }
          .px-6 { padding-left: 0.875rem !important; padding-right: 0.875rem !important; }
          .px-5 { padding-left: 0.75rem !important; padding-right: 0.75rem !important; }
          /* Remove max-width constraints so forms use full width */
          .max-w-3xl, .max-w-4xl, .max-w-2xl, .max-w-xl { max-width: 100% !important; }
          /* Reduce grid gaps */
          .gap-4 { gap: 0.625rem !important; }
          .gap-5 { gap: 0.75rem !important; }
          /* Make space-y tighter */
          .space-y-4 > * + * { margin-top: 0.75rem !important; }
          .space-y-5 > * + * { margin-top: 0.875rem !important; }
          /* Smaller text in tables */
          table td, table th { font-size: 0.7rem !important; padding: 0.375rem 0.5rem !important; }
          /* Full width selects and inputs */
          select, input[type="text"], input[type="date"], input[type="number"], input[type="email"], textarea { width: 100% !important; }
          /* Action buttons wrap */
          .flex.gap-1\.5 { flex-wrap: wrap; }
          /* Notification dropdown full width */
          .w-96 { width: calc(100vw - 1rem) !important; right: 0.5rem !important; left: auto !important; }
          /* ALL module pages can scroll horizontally for tables */
          main { overflow-x: hidden !important; }
          main > div { overflow-x: hidden !important; }
          /* Each overflow-x-auto container scrolls independently */
          .overflow-x-auto { overflow-x: auto !important; max-width: 100% !important; }
          .overflow-visible { overflow: visible !important; }
        }
        /* Touch improvements */
        button { touch-action: manipulation; cursor: pointer; }
        input, select, textarea { touch-action: manipulation; font-size: 16px !important; }
        /* Prevent iOS text size adjust */
        html { -webkit-text-size-adjust: 100%; text-size-adjust: 100%; }
        /* Make overflow-x-auto work on iOS Safari */
        .overflow-x-auto { -webkit-overflow-scrolling: touch; overflow-x: auto !important; }
        /* Ensure module pages can scroll horizontally */
        main > div { max-width: 100%; }
        /* Tables always scrollable */
        .table-scroll { overflow-x: auto; -webkit-overflow-scrolling: touch; width: 100%; }
      `}</style>
      {toast && <Toast message={toast.message} type={toast.type} onClose={hideToast} />}
      <Sidebar active={page} onNav={(pg) => navigate(pg, {})} collapsed={collapsed} mobileOpen={mobileOpen} onMobileClose={() => setMobileOpen(false)} user={user} onSignOut={() => supabase.auth.signOut()} />
      <div className="flex flex-col flex-1 min-w-0 overflow-y-hidden">
        <Header
          title={PAGE_TITLES[page] || "AGBC"}
          onToggle={() => setCollapsed(c => !c)}
          onMobileOpen={() => setMobileOpen(true)}
          user={user}
          unreadCount={unreadCount}
          notifs={notifs}
          onMarkRead={markRead}
          onMarkAll={markAllRead}
          onDelete={deleteNotif}
          onNavigate={navigate}
        />
        <main className="flex-1 overflow-y-auto pb-safe">{renderPage()}</main>
      </div>
    </div>
  );
}